(self.webpackChunk=self.webpackChunk||[]).push([[146],{4806:(e,s,n)=>{"use strict";n.r(s),n.d(s,{data:()=>t});const t={key:"v-93a4e8c8",path:"/docker/docker-remote.html",title:"docker 远程连接配置",lang:"en-US",frontmatter:{title:"docker 远程连接配置"},excerpt:"",headers:[{level:2,title:"配置",slug:"配置",children:[]},{level:2,title:"防火墙开启对应端口",slug:"防火墙开启对应端口",children:[]}],filePathRelative:"docker/docker-remote.md",git:{updatedTime:1626154667e3,contributors:[]}}},7954:(e,s,n)=>{"use strict";n.r(s),n.d(s,{default:()=>a});const t=(0,n(6252).uE)('<h2 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h2><blockquote><p>修改/etc/docker/daemon.json (不推荐)</p></blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>  {\n    &quot;hosts&quot;: [&quot;unix:///var/run/docker.sock&quot;, &quot;tcp://0.0.0.0:2375&quot;]\n    }\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>如果使用service启动的docker，并不会生效，会报配置错误</li></ul><blockquote><p>修改service配置</p></blockquote><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>sudo systemctl edit docker.service\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>打开一个覆盖docker.service的配置文件</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>[Service]\nExecStart=\nExecStart=/usr/bin/dockerd -H fd:// -H tcp://0.0.0.0:2375\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>保存，重启systemctl配置</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>sudo systemctl daemon-reload\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>重启docker</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>sudo systemctl restart docker.service\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>检查端口是否开启</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>$ sudo netstat -nltp | grep dockerd\ntcp6       0      0 :::2375                 :::*                    LISTEN\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="防火墙开启对应端口" tabindex="-1"><a class="header-anchor" href="#防火墙开启对应端口" aria-hidden="true">#</a> 防火墙开启对应端口</h2><ul><li>官网 <img src="/docker/docker-remote/docker-remote-1.png" alt=""></li><li>centos自定义Service 创建/etc/firewalld/services/docker.xml</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;?xml version=&quot;1.0&quot; encoding=&quot;utf-8&quot;?&gt;\n&lt;service&gt;\n     &lt;short&gt;docker&lt;/short&gt;\n      &lt;description&gt;docker daemon for remote access&lt;/description&gt;\n      &lt;port protocol=&quot;tcp&quot; port=&quot;2375&quot;/&gt;\n &lt;/service&gt;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>查看默认zone(一般是public)</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>firewall-cmd --get-default-zone\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>在zone中加入这个service</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>firewall-cmd --zone=public --add-service=docker --permanent\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>重新加载</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>firewall-cmd --reload\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',23),a={render:function(e,s){return t}}}}]);